function normalizeBold(text) {
  // transforma **negrito** em *negrito*
  return text.replace(/\*\*(.+?)\*\*/g, '*$1*');
}

function addBreaksAfterPeriods(text) {
  // coloca \n\n após ".", "!" ou "?" quando vier seguido de espaço
  return text.replace(/([.!?])\s+/g, '$1\n\n');
}

function splitIntoChunks(text, maxLen = 200) {
  const parts = [];
  const lines = text
    .split(/\n{2,}/) // blocos por parágrafo
    .map(s => s.trim())
    .filter(Boolean);

  for (const block of lines) {
    if (block.length <= maxLen) {
      parts.push(block);
      continue;
    }

    // tenta quebrar por frases
    const sentences = block.split(/(?<=[.!?])\s+/);
    let buf = '';

    for (const s of sentences) {
      const sentence = s.trim();
      if (!sentence) continue;

      if ((buf + (buf ? ' ' : '') + sentence).length <= maxLen) {
        buf += (buf ? ' ' : '') + sentence;
      } else {
        if (buf) parts.push(buf.trim());
        // se a frase sozinha for maior que maxLen, quebra “na marra”
        if (sentence.length > maxLen) {
          for (let i = 0; i < sentence.length; i += maxLen) {
            parts.push(sentence.slice(i, i + maxLen).trim());
          }
          buf = '';
        } else {
          buf = sentence;
        }
      }
    }
    if (buf) parts.push(buf.trim());
  }

  return parts.filter(Boolean);
}

