function normalizarTelefone(input) {
  if (!input) return null;
  let numero = String(input).replace(/\D/g, '');
  if (numero.startsWith('5555')) {
    numero = numero.replace(/^555+/, '55');
  }
  if (numero.startsWith('55')) {
    numero = numero.slice(2);
  }
  if (numero.length < 10 || numero.length > 11) {
    return null;
  }
  const ddd = numero.slice(0, 2);
  let telefone = numero.slice(2);
  if (telefone.length === 8) {
    telefone = '9' + telefone;
  }
  if (!telefone.startsWith('9')) {
    telefone = '9' + telefone.slice(1);
  }
  const telefoneFinal = `55${ddd}${telefone}`;
  if (telefoneFinal.length !== 13) {
    return null;
  }
  return telefoneFinal;
}

function formatarData(input) {
  if (!input) return null;
  const data = new Date(input);
  const dia = String(data.getDate()).padStart(2, '0');
  const mes = String(data.getMonth() + 1).padStart(2, '0');
  const ano = data.getFullYear();
  return `${dia}/${mes}/${ano}`;
}

