const dados = $('BUSCAR CLIENTE').item.json;

const saudacao = dados.frase_saudacao || '';
const encerramento = dados.frase_encerramento || '';
const perguntas = dados.perguntas_texto || '';
const nomeEscritorio = dados.nome_cliente || '';
const numPerguntas = String(dados.num_perguntas || 0);

function substituir(template) {
  return (template || '')
    .replace(/\{\{SAUDACAO\}\}/g, saudacao)
    .replace(/\{\{PERGUNTAS\}\}/g, perguntas)
    .replace(/\{\{ENCERRAMENTO\}\}/g, encerramento)
    .replace(/\{\{NOME_ESCRITORIO\}\}/g, nomeEscritorio)
    .replace(/\{\{NUM_PERGUNTAS\}\}/g, numPerguntas);
}

return [{ json: {
  ...dados,
  prompt_montado: substituir(dados.prompt_agente),
  prompt_resumo_montado: substituir(dados.prompt_resumo)
}}];

const output = $json.output || '';
const frase = $('DADOS LEAD').item.json.frase_encerramento || '';

return [{
  json: {
    ...$json,
    ai_output: output,
    is_encerramento: output.toLowerCase().trim().includes(frase.toLowerCase().trim())
  }
}];
